import{_ as e,o as r,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Harness 最佳实践","description":"","frontmatter":{},"headers":[],"relativePath":"guide/harness/best-practices.md","filePath":"guide/harness/best-practices.md","lastUpdated":null}'),o={name:"guide/harness/best-practices.md"};function s(l,a,n,c,h,d){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="harness-最佳实践" tabindex="-1">Harness 最佳实践 <a class="header-anchor" href="#harness-最佳实践" aria-label="Permalink to &quot;Harness 最佳实践&quot;">​</a></h1><h2 id="_1-场景小而稳" tabindex="-1">1. 场景小而稳 <a class="header-anchor" href="#_1-场景小而稳" aria-label="Permalink to &quot;1. 场景小而稳&quot;">​</a></h2><p>每个场景只验证一个能力点，避免“一个失败全盘失败”。</p><h2 id="_2-评估器组合" tabindex="-1">2. 评估器组合 <a class="header-anchor" href="#_2-评估器组合" aria-label="Permalink to &quot;2. 评估器组合&quot;">​</a></h2><p>不要只用单一评估器；推荐 <code>contains + no-error + json-valid</code> 组合。</p><h2 id="_3-mock-优先" tabindex="-1">3. Mock 优先 <a class="header-anchor" href="#_3-mock-优先" aria-label="Permalink to &quot;3. Mock 优先&quot;">​</a></h2><p>日常回归用 Mock，真实 API 仅做冒烟。</p><h2 id="_4-指标可追踪" tabindex="-1">4. 指标可追踪 <a class="header-anchor" href="#_4-指标可追踪" aria-label="Permalink to &quot;4. 指标可追踪&quot;">​</a></h2><p>至少追踪三项：</p><ul><li>通过率</li><li>平均时延</li><li>回归失败 Top3 原因</li></ul><h2 id="_5-失败可诊断" tabindex="-1">5. 失败可诊断 <a class="header-anchor" href="#_5-失败可诊断" aria-label="Permalink to &quot;5. 失败可诊断&quot;">​</a></h2><p>每次失败保留：输入、模型输出、评估器细节、环境信息。</p><h2 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h2><ul><li>场景写得太泛，无法定位问题</li><li>只看通过率，不看失败分布</li><li>评估器阈值过高或过低</li></ul>',14)])])}const p=e(o,[["render",s]]);export{u as __pageData,p as default};
